framework_css:
:root {
  --color-primary-orange: #FF9F3B;
  --color-primary-green: #50B15B;
  --color-secondary-ink: #2F3C4A;
  --color-secondary-soft: #F6F7F9;
  --color-neutral-white: #FFFFFF;
  --color-neutral-100: #F5F5F5;
  --color-neutral-600: #555C64;
  --color-semantic-success: #50B15B;
  --color-semantic-error: #E3564F;
  --color-semantic-warning: #FFB648;
  --color-semantic-info: #2F8DDA;

  --font-heading: 'Poppins', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;

  --font-size-h1: 44px;
  --font-size-h2: 34px;
  --font-size-h3: 26px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --radius-card: 24px;
  --radius-pill: 999px;
  --radius-input: 6px;

  --shadow-card: 0 18px 45px rgba(0, 0, 0, 0.16);

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
  scroll-behavior: smooth;
}

body.site-body {
  margin: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: 1.5;
  color: var(--color-neutral-600);
  background-color: var(--color-secondary-ink);
}

.page-background {
  min-height: 100vh;
  background:
    linear-gradient(180deg, rgba(47, 60, 74, 0.88) 0%, rgba(47, 60, 74, 0.92) 42%, rgba(47, 60, 74, 1) 100%),
    url('hero-moving-bg.jpg') center top / cover no-repeat fixed;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus-visible {
  outline: 2px solid var(--color-primary-orange);
  outline-offset: 2px;
}

.container {
  width: 100%;
  max-width: 1120px;
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Header */

.site-header {
  padding-top: var(--space-5);
  padding-bottom: var(--space-6);
}

.nav-shell {
  max-width: 1120px;
  margin: 0 auto;
  padding: var(--space-3) var(--space-5);
  background-color: var(--color-neutral-white);
  border-radius: var(--radius-card);
  box-shadow: var(--shadow-card);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
}

.brand-mark {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background:
    linear-gradient(135deg, var(--color-primary-green), var(--color-primary-orange));
  position: relative;
}

.brand-mark::before,
.brand-mark::after {
  content: '';
  position: absolute;
  inset: 9px;
  border-radius: 10px;
  border: 2px solid rgba(255, 255, 255, 0.9);
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-line {
  font-family: var(--font-heading);
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.brand-line-primary {
  font-weight: 600;
  font-size: 14px;
  color: var(--color-primary-green);
}

.brand-line-secondary {
  font-weight: 700;
  font-size: 16px;
  color: var(--color-secondary-ink);
}

.primary-nav {
  flex: 1;
}

.nav-list {
  list-style: none;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: var(--space-4);
  margin: 0;
  padding: 0;
  flex-wrap: wrap;
}

.nav-link {
  font-family: var(--font-heading);
  font-size: 15px;
  font-weight: 500;
  color: var(--color-secondary-ink);
  padding: 6px 2px;
  border-radius: 16px;
  transition: color 0.18s ease, background-color 0.18s ease;
}

.nav-link:hover {
  color: var(--color-primary-orange);
}

.nav-link.nav-link-cta {
  padding: 10px 22px;
  border-radius: var(--radius-pill);
  background-color: var(--color-primary-orange);
  color: var(--color-neutral-white);
  box-shadow: 0 10px 24px rgba(255, 159, 59, 0.38);
  white-space: nowrap;
}

.nav-link.nav-link-cta:hover {
  background-color: #ff9322;
}

/* Main */

.site-main {
  background-color: transparent;
}

.hero-shell {
  padding-bottom: var(--space-6);
}

.hero-inner {
  min-height: 220px;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  color: var(--color-neutral-white);
}

.content-shell {
  background-color: var(--color-secondary-soft);
  border-radius: 40px 40px 0 0;
  padding-top: var(--space-6);
  padding-bottom: var(--space-7);
}

/* Footer */

.site-footer {
  background-color: var(--color-secondary-ink);
  color: var(--color-secondary-soft);
}

.footer-upper {
  padding-top: var(--space-7);
  padding-bottom: var(--space-5);
}

.footer-grid {
  display: grid;
  grid-template-columns: 2.2fr 1.4fr 1.4fr;
  gap: var(--space-6);
}

.brand-footer .brand-line-primary {
  color: var(--color-neutral-white);
}

.brand-footer .brand-line-secondary {
  color: var(--color-neutral-white);
}

.footer-summary {
  margin-top: var(--space-3);
  max-width: 340px;
  font-size: var(--font-size-small);
  color: rgba(246, 247, 249, 0.78);
}

.footer-heading {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-size: 17px;
  font-weight: 600;
  color: var(--color-neutral-white);
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: grid;
  gap: var(--space-2);
}

.footer-links a {
  font-size: 15px;
  color: rgba(246, 247, 249, 0.82);
  transition: color 0.18s ease;
}

.footer-links a:hover {
  color: var(--color-primary-orange);
}

.footer-lower {
  border-top: 1px solid rgba(255, 255, 255, 0.08);
  padding: var(--space-3) 0 var(--space-4);
}

.footer-lower-inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-3);
  font-size: var(--font-size-small);
  color: rgba(246, 247, 249, 0.7);
}

@media (max-width: 960px) {
  .nav-shell {
    flex-direction: column;
    align-items: stretch;
    gap: var(--space-3);
  }

  .primary-nav {
    width: 100%;
  }

  .nav-list {
    justify-content: flex-start;
    row-gap: var(--space-2);
  }

  .footer-grid {
    grid-template-columns: 1.6fr 1fr;
  }
}

@media (max-width: 720px) {
  .site-header {
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
  }

  .nav-shell {
    padding: var(--space-3);
    border-radius: 18px;
  }

  .brand-mark {
    width: 38px;
    height: 38px;
  }

  .footer-grid {
    grid-template-columns: 1fr;
  }

  .footer-lower-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .content-shell {
    border-radius: 32px 32px 0 0;
  }
}
